*  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
function widgetClientController ($scope, $location, spUtil, $rootScope, $timeout, spAriaUtil, spGtd, $window) {		
	var c = this;

	// STRY0120675
	$rootScope.$on("$locationChangeSuccess", function(e, newUrl){
		// if sys_id changed, then update ids
		// // STRY0125255 - STRY0123997
		if($location.search().sys_id != c.data.sys_id ||
			 $location.search().table != c.data.table ||
			$location.search().selTab != c.data.selTab ||
			$location.search().p != c.data.page_index){
			c.data.sys_id = $location.search().sys_id;
			c.data.table = $location.search().table; 
			c.data.selTab = $location.search().selTab;
			c.data.page_index = $location.search().p;
			updateURLs(c.data.menu.items);
		}

	});

	// DFCT0011366
	$rootScope.$on("$discover-url-changed", function(params){

		c.data.sys_id = params.sys_id;
		c.data.selTab = params.selTab;
		c.data.page_index = params.page_index;
		c.data.table = params.table;
		if($location.search().sys_id != c.data.sys_id ||
			 $location.search().table != c.data.table ||
			$location.search().selTab != c.data.selTab ||
			$location.search().p != c.data.page_index){
			c.data.sys_id = $location.search().sys_id;
			c.data.table = $location.search().table; 
			c.data.selTab = $location.search().selTab;
			c.data.page_index = $location.search().p;
			updateURLs(c.data.menu.items);
		}

	});

	// // STRY0120675 there is a very similar server script
	function updateURLs(items){
		for (var i in items){
			var item = items[i];
			var currentHref = item.href;
			if(item.href && item.baseURL){
				item.href = item.baseURL;
			}
			// if URL has sys_id, then update it
			if(currentHref && c.data.sys_id && c.data.sys_id != ""){
				// add new sys_id
				item.href = item.href + "&sys_id=" + c.data.sys_id;
			}
			// if URL has table, then update it
			if(currentHref && c.data.table && c.data.table != ""){
				// add new table
				item.href = item.href + "&table=" + c.data.table;
			}

			// STRY0125255 - STRY0123997
			// if URL has selTab (selected tab), then update it
			if(currentHref && c.data.selTab && c.data.selTab != ""){
				// add new table
				item.href = item.href + "&selTab=" + c.data.selTab;
			}
			// if URL has p (page index), then update it
			if(currentHref && c.data.page_index && c.data.page_index != ""){
				// add new table
				item.href = item.href + "&p=" + c.data.page_index;
			}

			// if item has items recurse
			if(item.items && item.items.length > 0){
				updateURLs(item.items);
			}
			// process the scripted items also
			if(item.scriptedItems && item.scriptedItems.items && item.scriptedItems.items.length > 0){
				updateURLs(item.scriptedItems.items);
			}
		}
	}
	$scope.collapse = function() {
		$rootScope.$emit('sp-navbar-collapse');
	}
	$scope.loadingIndicator = $rootScope.loadingIndicator;
	$scope.itemAddedTooltipOpen = false;
	$scope.accessibilityEnabled = spAriaUtil.g_accessibility === "true";

	var cancelTooltipPromise;

	$scope.$on('sp_loading_indicator', function(e, value) {
		$scope.loadingIndicator = value;
	});
	// PRB1108244: visibleItems array is used to improve keyboard nav
	// in menu, refresh it as needed
	$scope.$watch('data.menu.items', function() {
		$scope.visibleItems = [];
		if ($scope.data.menu.items) {
			for (var i in $scope.data.menu.items) {
				var item = $scope.data.menu.items[i];
				if (item.items || (item.scriptedItems && item.scriptedItems.count != 0)){
					$scope.visibleItems.push(item);
				}

			}
		}
	}, true);

	// STRY0126152
	c.subItemSelected = function(item){		
		if(item.menuName && item.menuName.length >0){
			$scope.data.menuName = item.menuName;
			$scope.data.page_id = item.id;
			$scope.data.defaultPageChanged = true;
			if(	$scope.data.defaultPageChanged==true) {
				spUtil.update($scope);
			}			
		}
	}
	// set the user's default home page
	c.pageChanged = function(item){
		if(item.src == "Task_Black24.svg" && 
			c.data.settings.userDefaultLandingPage != "my_task_home_page"){
			$scope.data.newPage = "my_task_home_page";
			$scope.data.pageChanged=true;
		} else if(item.src == "TaskManager_Black24.svg" && 
			c.data.settings.userDefaultLandingPage != "my_ous_tasks_home_page"){
			$scope.data.newPage = "my_ous_tasks_home_page";
			$scope.data.pageChanged=true;
		}
		if(	$scope.data.pageChanged==true) {
			spUtil.update($scope);
		}
	}

	// Get list of record watchers
	var record_watchers = [];
	if ($scope.data.menu.items) {
		for(var i in $scope.data.menu.items) {
			var item = $scope.data.menu.items[i];
			if (item.type == 'scripted') {
				if (item.scriptedItems.record_watchers)
					record_watchers = record_watchers.concat(item.scriptedItems.record_watchers);
			}
			if (item.type == 'filtered') {
				record_watchers.push({'table':item.table,'filter':item.filter});
			}
		}
	}
	// Init record watchers
	for (var y in record_watchers){
		var watcher = record_watchers[y];
		spUtil.recordWatch($scope, watcher.table, watcher.filter);
	}
  $rootScope.$broadcast('sp-header-loaded');
}

sp_widget.css:
.dtech-header-menu-items{
  display: flex;
  flex-flow: row wrap;
  justify-content:center;
  align-items:start;
}

.dtech-dropdown-menu-align-center{
  padding: 0;
}
.label-tab {/*Tab Styling*/
  display: inline-block;
  /* needed height to get border outside the svg*/
  height: 42px;
  margin: 0 0 -1px;
/* NOTE: Shawn requested what is below, need to get the anchor tag to take up it's full space for this to work as the padding is pushing the anchor down without increasing the size of the row 
  padding: 15px 5px; 
  STRY0126833 changed right padding 20 2
  padding: 0px 15px 0px 0px;
  */
  padding: 0px 2px 0px 0px;
  border-radius: 5px;
  font-weight: 400;
  text-align: center;
  color: rgba(0, 0, 0, 1);
  cursor: pointer;
}
.label-tab > a {
	height: 42px;
  padding: 10px;
  border-radius: 5px;
}

/* the divider does not apply the hover state or selected*/
.divider-tab {/*Tab Styling*/
  display: inline-block;
  /* needed height to get border outside the svg*/
  height: 42px;
  margin: 0 0 -1px;
/* NOTE: Shawn requested what is below, need to get the anchor tag to take up it's full space for this to work as the padding is pushing the anchor down without increasing the size of the row 
  padding: 15px 5px; 
  STRY0126833 removed right padding
  padding: 0px 15px 0px 0px;
  */
  padding: 0;
  cursor: none;
  font-weight: 400;
  text-align: center;
  color: rgba(0, 0, 0, 1);
}

.divider-tab > a {
  cursor:default;
}
.label-tab > a:hover {/*Blue line on Hover*/
  background-color: rgba(217, 237, 247, 1);
}

.dtech-menu-hover >li > a:hover{
  background-color: rgba(217, 237, 247, 1);
}
.dtech-menu-label-selected > a {
  border-bottom: 5px solid rgba(20, 146, 230, 0.5);
}

.label-tab:focus {/*Blue line on Hover*/
  outline: 2px solid rgba(20, 146, 230, 1); 
  border-radius: 5px;
}


.dtech-menu-color {
  color:$tasker-color-blue-dark-35363a
}
.header-loader {
	float: left;
  	width: 24px;
  	position: relative;
  	top: 24px;
}



